<?php
declare(strict_types=1);require dirname(__DIR__).'/bootstrap.php';use VP3\Sales\LeadService;$admin=vp3_require_admin_permission('sales.manage');$id=(int)vp3_input('id');$service=new LeadService(vp3_db());$row=null;if($id){$stmt=vp3_db()->prepare('SELECT * FROM leads WHERE id=?');$stmt->execute([$id]);$row=$stmt->fetch();if(!$row){http_response_code(404);exit('Lead not found.');}}
if(vp3_method()==='POST'){vp3_verify_csrf();$action=vp3_input('action','save');try{if($action==='save'){if($id){vp3_db()->prepare('UPDATE leads SET assigned_admin_id=NULLIF(?,0),name=?,email=?,phone=NULLIF(?,\'\'),company_name=NULLIF(?,\'\'),project_name=NULLIF(?,\'\'),project_type=NULLIF(?,\'\'),budget_range=NULLIF(?,\'\'),target_launch_date=NULLIF(?,\'\'),summary=?,priority=?,updated_at=NOW() WHERE id=?')->execute([(int)vp3_input('assigned_admin_id'),vp3_input('name'),strtolower(vp3_input('email')),vp3_input('phone'),vp3_input('company_name'),vp3_input('project_name'),vp3_input('project_type'),vp3_input('budget_range'),vp3_input('target_launch_date'),vp3_input('summary'),vp3_input('priority','normal'),$id]);}else{$created=$service->create($_POST,'admin');$id=(int)$created['id'];}}elseif($action==='stage'){$service->updateStage($id,vp3_input('stage'),(int)$admin['id'],vp3_input('next_follow_up_at'),vp3_input('lost_reason'));}elseif($action==='note'){$service->addNote($id,(int)$admin['id'],vp3_input('note'),vp3_input('visibility'));}elseif($action==='activity'){$service->activity($id,(int)$admin['id'],vp3_input('activity_type','system'),vp3_input('title'),vp3_input('details'));}vp3_flash('success','Lead updated.');}catch(Throwable $e){vp3_flash('error',str_replace('_',' ',$e->getMessage()));}vp3_redirect('admin/lead.php?id='.$id);}
$admins=vp3_db()->query("SELECT id,name FROM admins WHERE status='active' ORDER BY name")->fetchAll();$notes=$activities=$demos=$proposals=[];if($id){$stmt=vp3_db()->prepare('SELECT n.*,a.name admin_name FROM lead_notes n JOIN admins a ON a.id=n.admin_id WHERE n.lead_id=? ORDER BY n.created_at DESC');$stmt->execute([$id]);$notes=$stmt->fetchAll();$stmt=vp3_db()->prepare('SELECT la.*,a.name admin_name FROM lead_activities la LEFT JOIN admins a ON a.id=la.admin_id WHERE la.lead_id=? ORDER BY la.occurred_at DESC');$stmt->execute([$id]);$activities=$stmt->fetchAll();$stmt=vp3_db()->prepare('SELECT * FROM demo_requests WHERE lead_id=? ORDER BY created_at DESC');$stmt->execute([$id]);$demos=$stmt->fetchAll();$stmt=vp3_db()->prepare('SELECT id,proposal_number,title,total_cents,currency,status,created_at FROM proposals WHERE lead_id=? ORDER BY created_at DESC');$stmt->execute([$id]);$proposals=$stmt->fetchAll();$stmt=vp3_db()->prepare('SELECT * FROM leads WHERE id=?');$stmt->execute([$id]);$row=$stmt->fetch();}
$pageTitle=$row?'Lead · '.$row['name']:'Add Lead';require VP3_ROOT.'/includes/admin-header.php';?>
<div class="admin-page-head"><div><span class="admin-kicker">Sales pipeline</span><h1><?=vp3_e($pageTitle)?></h1></div><div class="form-actions"><a class="button secondary" href="leads.php">Back</a><?php if($id):?><a class="button" href="proposal.php?lead_id=<?=$id?>">Create proposal</a><?php endif;?></div></div><div class="admin-split"><form class="card admin-form" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="save"><div class="admin-form-grid"><div class="field"><label>Name</label><input name="name" required value="<?=vp3_e($row['name']??'')?>"></div><div class="field"><label>Email</label><input name="email" type="email" required value="<?=vp3_e($row['email']??'')?>"></div><div class="field"><label>Phone</label><input name="phone" value="<?=vp3_e($row['phone']??'')?>"></div><div class="field"><label>Company</label><input name="company_name" value="<?=vp3_e($row['company_name']??'')?>"></div><div class="field"><label>Project name</label><input name="project_name" value="<?=vp3_e($row['project_name']??'')?>"></div><div class="field"><label>Project type</label><input name="project_type" value="<?=vp3_e($row['project_type']??'')?>"></div><div class="field"><label>Budget</label><input name="budget_range" value="<?=vp3_e($row['budget_range']??'')?>"></div><div class="field"><label>Target launch</label><input name="target_launch_date" type="date" value="<?=vp3_e($row['target_launch_date']??'')?>"></div><div class="field"><label>Priority</label><select name="priority"><?php foreach(['low','normal','high','urgent'] as $v):?><option <?=($row['priority']??'normal')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Assigned</label><select name="assigned_admin_id"><option value="0">Unassigned</option><?php foreach($admins as $a):?><option value="<?=(int)$a['id']?>" <?=(int)($row['assigned_admin_id']??0)===(int)$a['id']?'selected':''?>><?=vp3_e($a['name'])?></option><?php endforeach;?></select></div><div class="field full"><label>Summary</label><textarea name="summary"><?=vp3_e($row['summary']??'')?></textarea></div></div><button class="button">Save lead</button></form><?php if($id):?><div><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="stage"><h3>Pipeline status</h3><div class="field"><label>Stage</label><select name="stage"><?php foreach(['new','qualified','discovery','proposal','negotiation','won','lost','archived'] as $v):?><option <?=($row['stage']??'new')===$v?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="field"><label>Next follow-up</label><input type="datetime-local" name="next_follow_up_at" value="<?=vp3_e($row['next_follow_up_at']?str_replace(' ','T',substr($row['next_follow_up_at'],0,16)):'')?>"></div><div class="field"><label>Lost reason</label><input name="lost_reason" value="<?=vp3_e($row['lost_reason']??'')?>"></div><button class="button small">Update stage</button></form><form class="card admin-section" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="note"><h3>Add note</h3><textarea name="note" required></textarea><select name="visibility"><option value="internal">Internal</option><option value="customer_safe">Customer safe</option></select><button class="button small">Add note</button></form></div><?php endif;?></div><?php if($id):?><section class="admin-section admin-split"><div><h2>Activity</h2><div class="activity-list"><?php foreach($activities as $a):?><article><strong><?=vp3_e($a['title'])?></strong><span><?=vp3_e(($a['admin_name']?:'System').' · '.$a['occurred_at'])?></span><p><?=vp3_e($a['details'])?></p></article><?php endforeach;?></div></div><div><h2>Notes</h2><div class="activity-list"><?php foreach($notes as $n):?><article><strong><?=vp3_e($n['admin_name'])?></strong><span><?=vp3_e($n['visibility'].' · '.$n['created_at'])?></span><p><?=nl2br(vp3_e($n['note']))?></p></article><?php endforeach;?></div><h2>Proposals</h2><?php foreach($proposals as $p):?><article class="card"><a href="proposal.php?id=<?=(int)$p['id']?>"><strong><?=vp3_e($p['proposal_number'].' · '.$p['title'])?></strong></a><p><?=vp3_e(vp3_money((int)$p['total_cents'],$p['currency']).' · '.$p['status'])?></p></article><?php endforeach;?><h2>Demo requests</h2><?php foreach($demos as $d):?><article class="card"><strong><?=vp3_e($d['preferred_date']?:'Date flexible')?></strong><p><?=vp3_e($d['meeting_format'].' · '.$d['status'].' · '.$d['timezone'])?></p></article><?php endforeach;?></div></section><?php endif;?>
